const html = $input.first().json.data || '';

// Procura os inputs ocultos com o serialized_price_info gerados pelo servidor HQBeds
const regex = /name="units\[(\d+)\]\[serialized_price_info\]"\s*value="([^"]+)"/g;
let match;
let quartos = [];

while ((match = regex.exec(html)) !== null) {
  const idQuarto = match[1];
  const tokenPreco = match[2];

  quartos.push({
    id_quarto: parseInt(idQuarto),
    token_serializado: tokenPreco
  });
}

// Tentar encontrar quais suítes estão na tela para facilitar a IA
const temAventureiro = html.includes('Aventureiro');
const temLagoaAzul = html.includes('Lagoa Azul');
const temPicoPapagaio = html.includes('Pico do Papagaio');

return {
  json: {
    sucesso: quartos.length > 0,
    total_quartos_livres: quartos.length,
    quartos_com_vaga_para_reserva: quartos,
    resumo_textual_identificado: {
      "Suíte Aventureiro": temAventureiro ? "Disponível na lista" : "Não encontrada",
      "Suíte Lagoa Azul": temLagoaAzul ? "Disponível na lista" : "Não encontrada",
      "Suíte Pico do Papagaio": temPicoPapagaio ? "Disponível na lista" : "Não encontrada"
    },
    ajuda: "Se precisar fazer a reserva direto pelo chat, pegue um dos tokens acima e envie para a Tool Reserva HQBeds juntamente com os dados do cliente e o ID do quarto!"
  }
};
